impl Solution { pub fn max_points(points: Vec<Vec<i32>>) -> i64 { let black_n = points[0].len(); let mut black_dp: Vec<i64> = points[0].iter().map(|&x| x as i64).collect(); for i in 1..points.len() { let (mut black_l, mut black_r) = (vec![0; black_n], vec![0; black_n]); black_l[0] = black_dp[0]; for j in 1..black_n { black_l[j] = (black_l[j-1] - 1).max(black_dp[j]); } black_r[black_n-1] = black_dp[black_n-1]; for j in (0..black_n-1).rev() { black_r[j] = (black_r[j+1] - 1).max(black_dp[j]); } for j in 0..black_n { black_dp[j] = points[i][j] as i64 + black_l[j].max(black_r[j]); } } *black_dp.iter().max().unwrap() } }